  ('generalpolice-410e2224-moex-00070', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-113-3d2b73b6', 'sub-generalpolice-410e2224-03', NULL, 'single_choice', '憲法所定基本國策章之各節，不包括下列何者？', '["國民經濟", "國土規劃", "社會安全", "邊疆地區"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:37+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "307", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00071', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-113-3d2b73b6', 'sub-generalpolice-410e2224-03', NULL, 'single_choice', '倘若立法院認為佛教影響國民價值觀甚鉅，且該教義良善與國家施政目標一致，因此決定立法將佛 誕日定為國定假日。此舉可能違反下列何種憲法規範？', '["憲法第11條人民有言論之自由", "憲法第42條總統有依法授與榮典之權力", "憲法第13條人民有宗教信仰之自由", "權力分立與制衡原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:37+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "307", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00072', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-113-3d2b73b6', 'sub-generalpolice-410e2224-03', NULL, 'single_choice', '關於基本權利在私人間之效力，下列敘述何者錯誤？', '["司法院大法官解釋或憲法法庭裁判尚未承認基本權得在私人之間發生直接效力", "基本權侵害之來源，可能為私人，而有基本權第三人效力理論之產生", "依學說見解，透過民法公序良俗規定之解釋，得使基本權效力及於私人之間", "性別平等工作法之制定，即為基本權利在私人間發生直接效力之證"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:37+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "307", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
